 50	const rendererInfoStyle = kialiStyle({
 51	  marginBottom: '-0.125rem',
 52	  marginRight: '0',
 53	  marginTop: '0'
 54	});
 55	const workloadInfoStyle = kialiStyle({
 56	  verticalAlign: '-0.125rem'
 57	});
 58	// Links
 59	
 60	const getLink = (item: TResource, config: Resource, query?: string): string => {
 61	  let url = config.name === 'istio' ? getIstioLink(item) : `/namespaces/${item.namespace}/${config.name}/${item.name}`;
 62	
 63	  if (item.cluster && isMultiCluster && !url.includes('cluster')) {
 64	    if (url.includes('?')) {
 65	      url = `${url}&clusterName=${item.cluster}`;
 66	    } else {
 67	      url = `${url}?clusterName=${item.cluster}`;
 68	    }
 69	  }
 70	
 71	  if (query) {
 72	    if (url.includes('?')) {
 73	      url = `${url}&${query}`;
 74	    } else {
 75	      url = `${url}?${query}`;
 76	    }
 77	  }
 78	
 79	  return url;
 80	};
 81	
 82	const getIstioLink = (item: TResource): string => {
 83	  return GetIstioObjectUrl(
 84	    item.name,
 85	    item.namespace,
 86	    getIstioObjectGVK(item['apiVersion'], item['kind']),
 87	    item.cluster
 88	  );
 89	};
