 91	// Cells
 92	export const actionRenderer = (key: string, action: React.ReactNode): React.ReactNode => {
 93	  return (
 94	    <Td role="gridcell" key={`VirtuaItem_Action_${key}`} style={{ verticalAlign: 'middle' }}>
 95	      {action}
 96	    </Td>
 97	  );
 98	};
