100	export const details: Renderer<AppListItem | WorkloadListItem | ServiceListItem> = (
101	  item: AppListItem | WorkloadListItem | ServiceListItem
102	) => {
103	  const isWorkload = item.instanceType === InstanceType.Workload;
104	  const isAmbientWaypoint = item.isWaypoint;
105	  const hasMissingApp = isWorkload && !item['appLabel'] && !item.isWaypoint;
106	  const hasMissingVersion = isWorkload && !item['versionLabel'] && !item.isWaypoint;
107	  const additionalDetails = (item as WorkloadListItem | ServiceListItem).additionalDetailSample;
108	  const spacer = isWorkload && hasMissingSidecar(item) && additionalDetails && additionalDetails.icon;
109	
110	  return (
111	    <Td
112	      role="gridcell"
113	      dataLabel="Details"
114	      key={`VirtuaItem_Details_${item.namespace}_${item.name}`}
115	      style={{ verticalAlign: 'middle', whiteSpace: 'nowrap' }}
116	    >
117	      <ul>
118	        {isWorkload && (
119	          <li>
120	            <WorkloadConfigValidation
121	              namespace={item.namespace}
122	              validations={item.validations}
123	              className={classes(workloadInfoStyle)}
124	            />
125	          </li>
126	        )}
127	
128	        {(isWorkload || item.instanceType === InstanceType.App) && hasMissingSidecar(item) && (
129	          <li>
130	            <MissingSidecar />
131	          </li>
132	        )}
133	
134	        {isWorkload && (hasMissingApp || hasMissingVersion) && (
135	          <li>
136	            <MissingLabel missingApp={hasMissingApp} missingVersion={hasMissingVersion} tooltip={false} />
137	          </li>
138	        )}
139	
140	        {spacer && ' '}
141	
142	        {additionalDetails && additionalDetails.icon && (
143	          <li style={{ marginBottom: '0.125rem' }}>
144	            {renderAPILogo(additionalDetails.icon, additionalDetails.title, 0)}
145	          </li>
146	        )}
147	
148	        {item.istioReferences?.length > 0 &&
149	          item.istioReferences.map(ir => (
150	            <li
151	              key={ir.namespace ? `${ir.objectGVK.Group}.${ir.objectGVK.Kind}_${ir.name}_${ir.namespace}` : ir.name}
152	              style={{ marginBottom: '0.125rem' }}
153	            >
154	              <PFBadge badge={GVKToBadge[getGVKTypeString(ir.objectGVK)]} position={TooltipPosition.top} />
155	              <IstioObjectLink
156	                name={ir.name}
157	                namespace={ir.namespace ?? ''}
158	                cluster={item.cluster}
159	                objectGVK={ir.objectGVK}
160	              >
161	                {ir.name}
162	              </IstioObjectLink>
163	            </li>
164	          ))}
165	
166	        {isAmbientWaypoint && (
167	          <li style={{ marginBottom: '0.125rem' }}>
168	            <PFBadge badge={PFBadges.Waypoint} position={TooltipPosition.top} />
169	            Waypoint Proxy
170	            <Tooltip
171	              key="tooltip_missing_label"
172	              position={TooltipPosition.top}
173	              content="Layer 7 service Mesh capabilities in Istio Ambient"
174	            >
175	              <KialiIcon.Info className={classes(infoStyle, rendererInfoStyle)} />
176	            </Tooltip>
177	          </li>
178	        )}
179	      </ul>
180	    </Td>
181	  );
182	};
