192	export const istioConfig: Renderer<NamespaceInfo> = (ns: NamespaceInfo) => {
193	  let validations: ValidationStatus = { namespace: ns.name, objectCount: 0, errors: 0, warnings: 0 };
194	
195	  if (!!ns.validations) {
196	    validations = ns.validations;
197	  }
198	
199	  const status = (
200	    <Td
201	      role="gridcell"
202	      dataLabel="Config"
203	      key={`VirtuaItem_IstioConfig_${ns.name}`}
