274	export const item: Renderer<TResource> = (item: TResource, config: Resource, badge: PFBadgeType) => {
275	  const key = `link_definition_${config.name}_${item.namespace}_${item.name}`;
276	  let serviceBadge = badge;
277	
278	  if (item['serviceRegistry']) {
279	    switch (item['serviceRegistry']) {
280	      case 'External':
281	        serviceBadge = PFBadges.ExternalService;
282	        break;
283	      case 'Federation':
284	        serviceBadge = PFBadges.FederatedService;
285	        break;
286	    }
287	  }
288	
289	  return (
290	    <Td
291	      role="gridcell"
292	      dataLabel="Name"
293	      key={`VirtuaItem_Item_${item.namespace}_${item.name}`}
294	      style={{ verticalAlign: 'middle' }}
295	    >
296	      <PFBadge badge={serviceBadge} position={TooltipPosition.top} />
297	      <Link key={key} to={getLink(item, config)}>
298	        {item.name}
299	      </Link>
300	    </Td>
301	  );
302	};
