319	export const namespace: Renderer<TResource> = (item: TResource) => {
320	  return (
321	    <Td
322	      role="gridcell"
323	      dataLabel="Namespace"
324	      key={`VirtuaItem_Namespace_${item.namespace}_${item.name}`}
325	      style={{ verticalAlign: 'middle' }}
326	    >
327	      <PFBadge badge={PFBadges.Namespace} position={TooltipPosition.top} />
328	      {item.namespace}
329	    </Td>
330	  );
331	};
332	
333	const labelActivate = (filters: ActiveFilter[], key: string, value: string, id: string): boolean => {
334	  return filters.some(filter => {
335	    if (filter.category === id) {
336	      if (filter.value.includes('=')) {
337	        const [k, v] = filter.value.split('=');
338	
339	        if (k === key) {
340	          return v.split(',').some(val => value.split(',').some(vl => vl.trim().startsWith(val.trim())));
341	        }
342	
343	        return false;
344	      }
345	
346	      return key === filter.value;
347	    } else {
348	      if (filter.category === appLabelFilter.category) {
349	        return filter.value === 'Present' && key === 'app';
350	      }
351	
352	      return filter.value === 'Present' && key === 'version';
353	    }
354	  });
355	};
356	
357	export const labels: Renderer<SortResource | NamespaceInfo> = (
358	  item: SortResource | NamespaceInfo,
359	  _: Resource,
360	  __: PFBadgeType,
361	  ___?: Health,
362	  statefulFilter?: StatefulFiltersRef
363	) => {
364	  let path = window.location.pathname;
365	  path = path.substring(path.lastIndexOf('/console') + '/console'.length + 1);
366	  const labelFilt = path === 'overview' ? NsLabelFilter : labelFilter;
367	  const filters = FilterHelper.getFiltersFromURL([labelFilt, appLabelFilter, versionLabelFilter]);
368	
369	  return (
370	    <Td
371	      role="gridcell"
372	      dataLabel="Labels"
373	      key={`VirtuaItem_Labels_${'namespace' in item && `${item.namespace}_`}${item.name}`}
374	      style={{ verticalAlign: 'middle', paddingBottom: '0.25rem' }}
375	    >
376	      {item.labels &&
377	        Object.entries(item.labels).map(([key, value], i) => {
378	          const label = `${key}=${value}`;
379	          const labelAct = labelActivate(filters.filters, key, value, labelFilt.category);
380	
381	          const isExactlyLabelFilter = FilterHelper.getFiltersFromURL([labelFilt]).filters.some(f =>
382	            f.value.includes(label)
383	          );
384	
385	          const labelComponent = (
386	            <Label
387	              key={`label_${i}`}
388	              name={key}
389	              value={value}
390	              style={{ cursor: isExactlyLabelFilter || !labelAct ? 'pointer' : 'not-allowed', whiteSpace: 'nowrap' }}
391	              onClick={(): void => {
392	                if (statefulFilter) {
393	                  if (labelAct) {
394	                    isExactlyLabelFilter && statefulFilter.current!.removeFilter(labelFilt.category, label);
395	                  } else {
396	                    statefulFilter.current!.filterAdded(labelFilt, label);
397	                  }
398	                }
399	              }}
400	            />
401	          );
402	
403	          return statefulFilter ? (
404	            <Tooltip
405	              key={`Tooltip_Label_${key}_${value}`}
406	              content={
407	                labelAct ? (
408	                  isExactlyLabelFilter ? (
409	                    <>Remove label from Filters</>
410	                  ) : (
411	                    <>Kiali can't remove the filter if is an expression</>
412	                  )
413	                ) : (
414	                  <>Add label to Filters</>
415	                )
416	              }
417	            >
418	              {labelComponent}
419	            </Tooltip>
420	          ) : (
421	            labelComponent
422	          );
423	        })}
424	    </Td>
425	  );
426	};
