481	          <ValidationObjectSummary
482	            id={`${item.name}-config-validation`}
483	            validations={[validation]}
484	            reconciledCondition={reconciledCondition}
485	          />
486	        </Link>
487	      ) : (
488	        <>N/A</>
489	      )}
490	    </Td>
491	  );
