494	export const serviceConfiguration: Renderer<ServiceListItem> = (item: ServiceListItem, config: Resource) => {
495	  const validation = item.validation;
496	  const linkQuery: string = item['type'] ? 'list=yaml' : '';
497	
498	  return (
499	    <Td
500	      role="gridcell"
501	      dataLabel="Configuration"
502	      key={`VirtuaItem_Conf_${item.namespace}_${item.name}`}
503	      style={{ verticalAlign: 'middle' }}
