333	const labelActivate = (filters: ActiveFilter[], key: string, value: string, id: string): boolean => {
334	  return filters.some(filter => {
335	    if (filter.category === id) {
336	      if (filter.value.includes('=')) {
337	        const [k, v] = filter.value.split('=');
338	
339	        if (k === key) {
340	          return v.split(',').some(val => value.split(',').some(vl => vl.trim().startsWith(val.trim())));
341	        }
342	
343	        return false;
344	      }
345	
346	      return key === filter.value;
347	    } else {
348	      if (filter.category === appLabelFilter.category) {
349	        return filter.value === 'Present' && key === 'app';
350	      }
351	
352	      return filter.value === 'Present' && key === 'version';
353	    }
354	  });
355	};
