 1	import * as React from 'react';
 2	import { Tr } from '@patternfly/react-table';
 3	import { Resource, hasHealth, RenderResource, GVKToBadge } from './Config';
 4	import { PromisesRegistry } from '../../utils/CancelablePromises';
 5	import { Health } from '../../types/Health';
 6	import { StatefulFiltersRef } from '../Filters/StatefulFilters';
 7	import { actionRenderer } from './Renderers';
 8	import { getGVKTypeString, getIstioObjectGVK, kindToStringIncludeK8s } from '../../utils/IstioConfigUtils';
 9	
10	type VirtualItemProps = {
11	  action?: JSX.Element;
12	  className?: string;
13	  columns: any[];
14	  config: Resource;
15	  index: number;
16	  item: RenderResource;
17	  statefulFilterProps?: StatefulFiltersRef;
18	  style?: React.CSSProperties;
19	};
20	
21	type VirtualItemState = {
22	  health?: Health;
23	};
24	
25	export class VirtualItem extends React.Component<VirtualItemProps, VirtualItemState> {
26	  private promises = new PromisesRegistry();
27	
28	  constructor(props: VirtualItemProps) {
29	    super(props);
30	    this.state = { health: undefined };
31	  }
32	
33	  componentDidMount(): void {
34	    if (hasHealth(this.props.item)) {
35	      this.setState({ health: this.props.item.health });
36	    }
37	  }
38	
39	  componentDidUpdate(prevProps: VirtualItemProps): void {
40	    if (hasHealth(this.props.item) && this.props.item.health !== prevProps.item['health']) {
41	      this.setState({ health: this.props.item.health });
42	    }
43	  }
44	
45	  componentWillUnmount(): void {
46	    this.promises.cancelAll();
47	  }
48	
49	  renderDetails = (item: RenderResource, health?: Health): React.ReactNode => {
50	    return this.props.columns
51	      .filter(object => !!object.renderer)
52	      .map(object => object.renderer(item, this.props.config, this.getBadge(), health, this.props.statefulFilterProps));
53	  };
54	
55	  getBadge = (): React.ReactNode => {
56	    // TODO this.props.item.type
57	    return this.props.config.name !== 'istio'
58	      ? this.props.config.badge
59	      : GVKToBadge[getGVKTypeString(getIstioObjectGVK(this.props.item['apiVersion'], this.props.item['kind']))];
60	  };
61	
62	  render(): React.ReactNode {
63	    const { style, className, item } = this.props;
64	    const cluster = item.cluster ? `_Cluster${item.cluster}` : '';
65	    const namespace = 'namespace' in item ? `_Ns${item.namespace}` : '';
66	    const type =
67	      'type' in item
68	        ? `_${item.type}`
69	        : 'kind' in item && 'apiVersion' in item
70	        ? `_${kindToStringIncludeK8s(item.apiVersion, item.kind)}`
71	        : 'gvk' in item
72	        ? `_${item.gvk.Kind}`
73	        : '';
74	    // End result looks like: VirtualItem_Clusterwest_Nsbookinfo_networking.istio.io.v1.Gateway_bookinfo-gateway
75	
76	    const key = `VirtualItem${cluster}${namespace}${type}_${item.name}`;
77	
78	    return (
79	      <Tr style={style} className={className} role="row" key={key} data-test={key}>
80	        {this.renderDetails(item, this.state.health)}
81	        {this.props.action && actionRenderer(key, this.props.action)}
82	      </Tr>
83	    );
84	  }
85	}

