79	      <Tr style={style} className={className} role="row" key={key} data-test={key}>
80	        {this.renderDetails(item, this.state.health)}
81	        {this.props.action && actionRenderer(key, this.props.action)}
82	      </Tr>
83	    );
84	  }
85	}

